// ===== Optionbar.js =====
import React from 'react';
import './Optionbar.css';
import {
    segmentOptions,
    highlightOptions,
    seasonOptions,
    locationOptions
} from './Icons/optionbarOptions';

export default function Optionbar({ filters, onChange }) {
    const groups = [
        { key:'segments',  title:'Segments',         options:segmentOptions },
        { key:'highlights',title:'Highlights',       options:highlightOptions },
        { key:'seasons',   title:'Seasons',          options:seasonOptions },
        { key:'locations', title:'Location Produced',options:locationOptions }
    ];
    const toggle = (k,id)=>{
        const s = new Set(filters[k]);
        s.has(id)?s.delete(id):s.add(id);
        onChange({ ...filters, [k]:s });
    };
    return (
        <nav className="optionbar-container">
            <h3 className="optionbar-title">Filters & Categories</h3>
            <div className="optionbar-scrollable">
                {groups.map((g,i)=>(
                    <div key={g.key} className="optionbar-group">
                        {i>0&&<hr className="optionbar-divider"/>}
                        <h4 className="optionbar-group-title">{g.title}</h4>
                        <ul className="optionbar-list">
                            {g.options.map(o=>(
                                <li key={o.id} className="option-item">
                                    <input
                                        type="checkbox"
                                        id={`${g.key}-${o.id}`}
                                        checked={filters[g.key].has(o.id)}
                                        onChange={()=>toggle(g.key,o.id)}
                                    />
                                    <label htmlFor={`${g.key}-${o.id}`} className="option-label">
                                        <img src={o.icon} alt={o.label} className="option-icon" /> {o.label}
                                    </label>
                                </li>
                            ))}
                        </ul>
                    </div>
                ))}
            </div>
        </nav>
    );
}
